INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (321, 1, 40011, 1, 1, "もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 2, 0, "リリ", 125801, 24001);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (322, 1, 40011, 1, 2, "初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, 0, "クリア", 126001, 24001);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (323, 1, 40011, 1, 3, "んーと。\nこれ、あげる。\nはい", 2, 0, "プレシア", 126101, 24001);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (324, 2, 40011, 1, 4, "あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 2, 0, "リリ", 125801, 24001);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (325, 2, 40011, 1, 5, "こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 2, 0, "クリア", 126001, 24001);
INSERT INTO `v1_21f11ceacc5caa550a5c038ee2bdd5588c9d701af6097f8ba5770bf031dbc166` VALUES (326, 2, 40011, 1, 6, "お兄。\nきてくれて、うれしい", 2, 0, "プレシア", 126101, 24001);
